package engine

import (
	"context"
	"errors"
	"io"
	"io/fs"
	"sort"
	"time"

	"github.com/agent-sync/agent-sync/internal/adapter/contract"
	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/ledger"
)

// planTarget computes the dry-run change set for one target without
// mutating the workspace. It runs the adapter (read-only) and diffs the
// desired ops against the current ledger and on-disk state.
func planTarget(ctx context.Context, req Request, target string, _ time.Time) TargetChange {
	change := TargetChange{Target: target}

	old, err := loadLedger(req.Root, target)
	if err != nil {
		change.Error = err.Error()
		return change
	}
	oldByPath := map[string]ledger.Entry{}
	for _, e := range old.Entries {
		oldByPath[e.Path] = e
	}

	out, err := runAdapter(ctx, req, target)
	if err != nil {
		change.Error = err.Error()
		return change
	}
	change.Warnings = out.warnings

	// Mirror applyTarget: operate on owned-subdir prefixes plus the managed
	// leaf dirs of shared-subdirs (never the shared parent) so deletion
	// accounting covers removed agent-sync leaves without flagging foreign
	// sibling content under a shared tree.
	effective := effectiveOwnedPrefixes(out.ownedPrefixes, out.sharedPrefixes, out.ops, old.Entries)

	desired := map[string]string{} // path -> sha256 (write_file only)
	for _, op := range out.ops {
		switch o := op.(type) {
		case contract.OpWriteFile:
			desired[o.Path] = sha256Hex(o.Content)
		case contract.OpWriteToolOwned:
			// Tool-owned slices: treat presence as an update candidate;
			// a precise slice diff is deferred (v1 merges idempotently).
			if _, known := oldByPath[o.Path]; known {
				change.WouldUpdate = append(change.WouldUpdate, o.Path)
			} else {
				change.WouldCreate = append(change.WouldCreate, o.Path)
			}
		}
	}

	for p, want := range desired {
		prev, known := oldByPath[p]
		switch {
		case !known:
			change.WouldCreate = append(change.WouldCreate, p)
		case prev.SHA256 != want:
			change.WouldUpdate = append(change.WouldUpdate, p)
		default:
			// Ledger says unchanged — check for out-of-band edits on disk.
			onDisk, rerr := readHash(req.Root, p)
			switch {
			case rerr == nil:
				if onDisk != prev.SHA256 {
					change.OutOfBand = append(change.OutOfBand, p)
				}
			case errors.Is(rerr, fs.ErrNotExist):
				// File expected by the ledger is gone — not an out-of-band
				// edit; the orphan/delete accounting covers absence.
			default:
				// A real read failure (permission, I/O) must not be silently
				// swallowed as "unchanged".
				change.Error = rerr.Error()
				return change
			}
		}
	}

	// Deletions: ledger paths under an owned subdir no longer desired.
	for _, e := range old.Entries {
		if ownerOf(effective, e.Path) == "" {
			continue
		}
		if _, stillWanted := desired[e.Path]; !stillWanted {
			change.WouldDelete = append(change.WouldDelete, e.Path)
		}
	}

	change.WouldCreate = sortedStrings(change.WouldCreate)
	change.WouldUpdate = sortedStrings(change.WouldUpdate)
	change.WouldDelete = sortedStrings(change.WouldDelete)
	change.OutOfBand = sortedStrings(change.OutOfBand)
	sort.Strings(change.Warnings)
	return change
}

// sortedStrings returns a sorted copy of in.
func sortedStrings(in []string) []string {
	out := append([]string(nil), in...)
	sort.Strings(out)
	return out
}

// readHash reads the file at relPath through the root and returns its
// sha256 hex. The error is returned verbatim (callers branch on
// fs.ErrNotExist) so real I/O/permission failures are never silently
// swallowed as "unchanged".
func readHash(root *fsroot.Root, relPath string) (string, error) {
	f, err := root.Inner().Open(relPath)
	if err != nil {
		return "", err
	}
	defer func() { _ = f.Close() }()
	data, err := io.ReadAll(f)
	if err != nil {
		return "", err
	}
	return sha256Hex(data), nil
}

package merge

import (
	"context"
	"errors"
	"fmt"
	"io"
	"io/fs"
	"path/filepath"
	"strings"

	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/locks"
	"github.com/agent-sync/agent-sync/pkg/adapterkit"
)

// ApplyToFile is the one filesystem-touching entry point: it holds the
// Unit 12 per-external-file flock across the whole read-merge-write,
// dispatches to the pure engine by locator kind, and writes the result
// atomically via fsroot (temp+fsync+rename). On any engine error it
// returns fail-closed — the on-disk file is left byte-identical.
//
// relPath is workspace-relative (forward-slash). holder is the adapter
// name, used in the per-file lock's timeout diagnostics.
func ApplyToFile(ctx context.Context, root *fsroot.Root, reg *locks.FileLockRegistry, relPath string, e MergeEntry, holder string) (sliceHash, warning string, err error) {
	abs := filepath.Join(root.Path(), filepath.FromSlash(relPath))
	release, err := reg.Acquire(ctx, abs, holder, locks.FileLockOpts{})
	if err != nil {
		return "", "", err
	}
	defer func() { _ = release() }()

	existing, err := readExisting(root, relPath)
	if err != nil {
		return "", "", err
	}

	var merged []byte
	switch e.Kind {
	case adapterkit.ToolOwnedKindJSONPointer:
		merged, sliceHash, err = mergeJSON(existing, e)
	case adapterkit.ToolOwnedKindTOMLPath:
		merged, sliceHash, err = mergeTOML(existing, e)
	case adapterkit.ToolOwnedKindMarkdownSection:
		merged, sliceHash, warning, err = mergeMarkdown(existing, e)
	default:
		return "", "", fmt.Errorf("merge: unknown locator kind %q", e.Kind)
	}
	if err != nil {
		return "", "", err // fail-closed: nothing written
	}

	// StagedWrite does not create parents; a nested target (.cursor/,
	// .codex/) on first sync needs the dir created first.
	if dir := slashDir(relPath); dir != "" {
		if mkErr := root.Inner().MkdirAll(dir, 0o755); mkErr != nil {
			return "", "", fmt.Errorf("merge: mkdir %s: %w", dir, mkErr)
		}
	}
	if werr := root.StagedWrite(relPath, merged, 0o644); werr != nil {
		return "", "", fmt.Errorf("merge: write %s: %w", relPath, werr)
	}
	return sliceHash, warning, nil
}

func readExisting(root *fsroot.Root, relPath string) ([]byte, error) {
	f, err := root.Inner().Open(relPath)
	if err != nil {
		if errors.Is(err, fs.ErrNotExist) {
			return nil, nil
		}
		return nil, fmt.Errorf("merge: read %s: %w", relPath, err)
	}
	defer func() { _ = f.Close() }()
	return io.ReadAll(f)
}

// slashDir returns the parent directory of a forward-slash relative
// path, or "" when the path is at the workspace root.
func slashDir(relPath string) string {
	i := strings.LastIndex(relPath, "/")
	if i <= 0 {
		return ""
	}
	return relPath[:i]
}

