func Sync(ctx context.Context, req Request) (report.Summary, error) {
	if req.Root == nil {
		return report.Summary{}, errors.New("engine: request root is nil")
	}
	if req.Registry == nil {
		return report.Summary{}, errors.New("engine: request registry is nil")
	}
	opts := req.Options
	now := opts.now()
	log := opts.logger()

	// Recovery is idempotent and global; drive any half-finished swap to a
	// clean state before touching anything.
	if _, err := syncpkg.Recover(req.Root, "."); err != nil {
		return report.Summary{}, err
	}

	targets := resolvedTargets(req.Targets, opts.TargetsFilter)
	var reports []report.TargetReport
	abort := false

	for _, target := range targets {
		if abort {
			reports = append(reports, report.TargetReport{Target: target, Status: report.StatusSkipped})
			continue
		}
		start := opts.now()
		res, err := applyTarget(ctx, req, target, now)
		dur := opts.now().Sub(start).Milliseconds()
		if err != nil {
			log.Error("target sync failed", "target", target, "err", err)
			tr := report.TargetReport{
				Target:     target,
				Status:     report.StatusFailed,
				DurationMs: dur,
				Error:      err.Error(),
			}
			reports = append(reports, tr)
			if opts.mode() == report.ModeAtomic {
				abort = true
			}
			continue
		}
		reports = append(reports, toTargetReport(target, res, dur))
	}

	// Capability report is best-effort observability; failure to persist
	// it never fails the sync.
	if err := writeCapabilityReport(ctx, req, now); err != nil {
		log.Warn("capability report not written", "err", err)
	}

	summary := report.Summarize(req.WorkspacePath, req.Commit, now.UTC().Format(time.RFC3339), opts.mode(), reports)
	return summary, nil
}

// Plan runs the pipeline up to (but not including) staging and returns
// the per-target change set without mutating the workspace. It powers
// `validate`.
func Plan(ctx context.Context, req Request) (PlanResult, error) {
	if req.Root == nil {
		return PlanResult{}, errors.New("engine: request root is nil")
	}
	if req.Registry == nil {
		return PlanResult{}, errors.New("engine: request registry is nil")
	}
	opts := req.Options
	now := opts.now()

	targets := resolvedTargets(req.Targets, opts.TargetsFilter)
	out := PlanResult{WorkspacePath: req.WorkspacePath, Commit: req.Commit}

	for _, target := range targets {
		change := planTarget(ctx, req, target, now)
		if len(change.WouldCreate) > 0 || len(change.WouldUpdate) > 0 || len(change.WouldDelete) > 0 || len(change.OutOfBand) > 0 {
			out.DriftDetected = true
		}
		out.Targets = append(out.Targets, change)
	}
	return out, nil
}

func toTargetReport(target string, res statusResult, dur int64) report.TargetReport {
	st := report.StatusOK
	switch res.status {
	case statusUnchanged:
		st = report.StatusUnchanged
	case statusBlocked:
		st = report.StatusBlocked
	}

type TargetChange struct {
	Target      string
	WouldCreate []string
	WouldUpdate []string
	WouldDelete []string
	Warnings    []string
	Error       string
	OutOfBand   []string // paths whose on-disk hash diverges from the ledger
}

// PlanResult is the result of a dry-run (validate). DriftDetected is true
// when any target has a non-empty change set or out-of-band modification.
type PlanResult struct {
	WorkspacePath string
	Commit        string
	Targets       []TargetChange
	DriftDetected bool
}

func (o Options) now() time.Time {

// emitAgentsMD writes the agents-md companion overlay into
// CLAUDE.md (workspace root) as a managed section between
// <!-- agent-sync:begin id=<id> --> and <!-- agent-sync:end id=<id> -->
// markers. CLAUDE.md is tool-owned by Claude Code; user content
// outside the managed section is preserved by the merge step
// (Unit 12a).
//
// The body is rejected when it contains the agent-sync marker opener.
// Without this guard a body containing `<!-- agent-sync:end id=other -->`
// could break out of its own section or forge another section
// entirely, leaving the merged CLAUDE.md with conflicting markers
// the merge step has no way to resolve safely.
//
// No managed-file header is added inside the section: the begin/end
// markers serve as the equivalent ownership advertisement, and a
// header inside a user-owned markdown file would be visually noisy.
func emitAgentsMD(emitted *emittedOps, node irNode) error {
	body, err := decodeBodyOrPassthrough(node.Body)
	if err != nil {
		return wrapBodyErr(node, err)
	}
	if bytes.Contains(body, markerOpenBytes) {
		return &adapterkit.Error{
			Code:    adapterkit.CodeInvalidParams,
			Message: fmt.Sprintf("claude: agents-md %q body contains agent-sync marker syntax (%q); refusing to corrupt CLAUDE.md", node.ID, string(markerOpenBytes)),
		}
	}
	wrapped := wrapManagedSection(node.ID, body)

	emitted.add(adapterkit.OpWriteToolOwned{
		Path:    claudeMDPath,
		Kind:    adapterkit.ToolOwnedKindMarkdownSection,
		Locator: sectionIDPrefix + node.ID,
		Content: wrapped,
	})
	return nil
}

